#include <stdio.h>

// Déclaration et définition de la fonction
float calculerMoyenne(float notes[], int taille) {
    float somme = 0.0;
    for (int i = 0; i < taille; i++) {
        somme = somme + notes[i];
    }
    return somme / taille;
}

int main() {
    int N;
    printf("Entrez le nombre de notes : ");
    scanf("%d", &N);

    float tableauNotes[N];
    for (int i = 0; i < N; i++) {
        printf("Entrez la note %d : ", i + 1);
        scanf("%f", &tableauNotes[i]);
    }

    float moyenne = calculerMoyenne(tableauNotes, N);
    printf("La moyenne est : %.2f\n", moyenne);

    return 0;
}
