void ajouterProduit(char noms[][50], int quantites[], int *nbProduits) {
    char nom[50];
    int qte, i;

    printf("Nom du produit : ");
    scanf("%s", nom);
    printf("Quantite a ajouter : ");
    scanf("%d", &qte);

    // Rechercher si le produit existe
    for (i = 0; i < *nbProduits; i++) {
        if (strcmp(noms[i], nom) == 0) {
            quantites[i] += qte;
            printf("Quantite mise a jour pour %s. Nouveau stock : %d\n", nom, quantites[i]);
            return;
        }
    }

    // Si non trouvé, ajouter un nouveau produit
    if (*nbProduits < 100) {
        strcpy(noms[*nbProduits], nom);
        quantites[*nbProduits] = qte;
        (*nbProduits)++;
        printf("Nouveau produit %s ajoute avec %d unites.\n", nom, qte);
    } else {
        printf("Stock plein, impossible d'ajouter un nouveau produit.\n");
    }
}
```
*Note : Il faudra inclure `<string.h>` pour utiliser `strcmp` et `strcpy`.*
